public:
    vector<int> numsSameConsecDiff(int n, int k) {
        vector<int> ans;
        if (n == 1) { ans.push_back(0); return ans; }
        queue<int> q;
        for (int d = 1; d <= 9; ++d) q.push(d);
        for (int len = 2; len <= n; ++len) {
            int sz = q.size();
            while (sz--) {
                int num = q.front(); q.pop();
                int last = num % 10;
                if (last + k <= 9) q.push(num * 10 + (last + k));
                if (k != 0 && last - k >= 0) q.push(num * 10 + (last - k));
            }
        }
        while (!q.empty()) { ans.push_back(q.front()); q.pop(); }
        return ans;
    }
};
